# Category: xss

from flask import Flask, request, render_template_string
import html
import re

app = Flask(__name__)

ALLOWED_TAGS = {"b", "strong", "i", "em"}

def sanitize_basic_formatting(value: str) -> str:
    if not value:
        return ""
    escaped = html.escape(value, quote=True)
    escaped = re.sub(r"&lt;\s*(/?)\s*(b|strong|i|em)\s*&gt;", r"<\1\2>", escaped, flags=re.IGNORECASE)
    return escaped

@app.route("/dashboard")
def dashboard():
    name = html.escape(request.args.get("name", "Guest"), quote=True)
    location = html.escape(request.args.get("location", "Unknown"), quote=True)
    bio = sanitize_basic_formatting(request.args.get("bio", "No bio provided."))
